#include<bits/stdc++.h>
using namespace std;
long long p[8000010],q[8000010];
long long sum[8000010],sum1[8000010];
char s[8000010];
const long long mod=19930726;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
int main()
{
    long long n,k;
    scanf("%lld%lld",&n,&k);
    long long tot=0;
    s[0]='~';
    scanf("%s",s+1);
    long long r=0,mid=0;
    for(long long i=1;i<=n;i++)
    {
        if(i<=r)
        {
            p[i]=min(p[mid*2-i],r-i+1);
        }
        while(s[i-p[i]]==s[i+p[i]])
        {
            p[i]++;
        }
        if(i+p[i]-1>=r)
        {
            r=i+p[i]-1;
            mid=i;
        }
    }
    for(long long i=1;i<=n;i++)
    {
        sum1[i]=1;
        q[i]=p[i]*2-1;
    }
    for(long long i=n;i>=1;i--)
    {
        sum[q[i]]++;
    }
    sum1[n+1]=sum[n+2]=1;
    for(long long i=n;i>=1;i--)if(i%2==1)
    {
        sum[i]+=sum[i+2];
        sum1[i]=fastpow(i,sum[i]);
    }
    for(long long i=n;i>=1;i--)if(i%2==1)
    {
        sum[i]+=sum[i+2];
        sum1[i]=sum1[i+2]*sum1[i]%mod;
    }
    for(long long i=n;i>=1;i--)if(i%2==1)
    {
        if(sum[i+2]<=k&&sum[i]>=k)
        {
            printf("%lld",sum1[i+2]*fastpow(i,k-sum[i+2])%mod);
            return 0;
        }
    }
    printf("-1");
    return 0;
}
